sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
	var logger = new Logger('CMDBCertificatesWebhook');
	var data = request.body.data;
	var auth = request.getHeader('Authorization').split(" ")[1];
	var userId = gs.base64Decode(auth).split(":")[0];
	var pluginService = new PluginService();

	try {
		if (data.length > 0 && !pluginService.isCMDBPluginActive()) {
			throw new Error("'Certificate Inventory and Management' plugin must be enabled to have access to CMDB functionality.");	
		}

		var service = new CMDBCertificateService();

		data.forEach(function (certificateDetails) {
			var subject = certificateDetails.subject;

			service.saveCertificate({
				certificate: certificateDetails.certificate,
				cert_template: certificateDetails.template_name,
				thumb_print: certificateDetails.thumbprint,
				key_size: certificateDetails.key_size,
				signature_algorithm: certificateDetails.signature_algorithm,
				subject_country: subject.country,
				subject_distinguished_name: subject.unstructured_name,
				subject_email: subject.email,
				subject_locality: subject.locality,
				subject_organization: subject.organization_name,
				subject_organizational_unit: subject.organization_units,
				subject_state: subject.state,
                valid_from: certificateDetails.valid_from,
                valid_to: certificateDetails.valid_to,
                issuer_common_name: certificateDetails.issuing_ca_name,
                subject_common_name: certificateDetails.common_name,
                serial_number: certificateDetails.serial_number,
				state: certificateDetails.status,
			});
		});

		logger.debug("Certificates chunk saved of length: {0}, userId: {1}", data.length, userId);
		response.setStatus(200);
	} catch (error) {
		logger.error("Failed to save certificates chunk of length: {0}, error: {1}, userId: {2}", data.length, error, userId);
		response.setStatus(500);
		response.setBody({
			error: error.message,
		});
	}
})(request, response);
